     1→/**
     2→ * Stateless MCP App rendering gateway.
     3→ *
     4→ * This server has NO filesystem access and NO knowledge of genes/YAML.
     5→ * The agent computes stats locally and passes them as tool input.
     6→ * The server just renders the data as an interactive HTML dashboard.
     7→ */
     8→import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
     9→import { StreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/streamableHttp.js";
    10→import { z } from "zod";
    11→import cors from "cors";
    12→import express from "express";
    13→import fs from "node:fs/promises";
    14→import path from "node:path";
    15→
    16→const RESOURCE_MIME_TYPE = "text/html;profile=mcp-app";
    17→
    18→// ── MCP Server ──────────────────────────────────────────────────────────
    19→
    20→const server = new McpServer({
    21→  name: "Gene Review Dashboard",
    22→  version: "1.0.0",
    23→});
    24→
    25→const DASHBOARD_URI = "ui://gene-review-dashboard/mcp-app.html";
    26→
    27→// The agent passes stats as input; the server just renders them
    28→server.registerTool(
    29→  "gene-review-dashboard",
    30→  {
    31→    title: "Gene Review Dashboard",
    32→    description:
    33→      "Renders an interactive dashboard showing gene annotation review status. " +
    34→      "The caller provides pre-computed stats (action counts, species counts, totals). " +
    35→      "Returns an interactive UI with bar charts and summary cards.",
    36→    inputSchema: {
    37→      total_genes: z.number().describe("Total number of genes reviewed"),
    38→      total_annotations: z.number().describe("Total number of annotations"),
    39→      total_species: z.number().describe("Total number of species"),
    40→      action_counts: z
    41→        .record(z.string(), z.number())
    42→        .describe("Map of action type (ACCEPT, MODIFY, REMOVE, etc.) to count"),
    43→      species_gene_counts: z
    44→        .record(z.string(), z.number())
    45→        .describe("Map of species code to gene count (top N)"),
    46→    },
    47→    _meta: { ui: { resourceUri: DASHBOARD_URI } },
    48→  },
    49→  async (args) => {
    50→    // Pass the stats straight through as the tool result for the UI to render
    51→    return {
    52→      content: [{ type: "text", text: JSON.stringify(args) }],
    53→    };
    54→  },
    55→);
    56→
    57→// Serve the bundled HTML
    58→server.resource(
    59→  "dashboard-ui",
    60→  DASHBOARD_URI,
    61→  { mimeType: RESOURCE_MIME_TYPE },
    62→  async () => {
    63→    const html = await fs.readFile(
    64→      path.join(import.meta.dirname, "dist", "mcp-app.html"),
    65→      "utf-8",
    66→    );
    67→    return {
    68→      contents: [{ uri: DASHBOARD_URI, mimeType: RESOURCE_MIME_TYPE, text: html }],
    69→    };
    70→  },
    71→);
    72→
    73→// ── HTTP transport ──────────────────────────────────────────────────────
    74→
    75→const app = express();
    76→app.use(cors());
    77→app.use(express.json());
    78→
    79→app.post("/mcp", async (req, res) => {
    80→  const transport = new StreamableHTTPServerTransport({
    81→    sessionIdGenerator: undefined,
    82→    enableJsonResponse: true,
    83→  });
    84→  res.on("close", () => transport.close());
    85→  await server.connect(transport);
    86→  await transport.handleRequest(req, res, req.body);
    87→});
    88→
    89→const PORT = Number(process.env.PORT ?? 3456);
    90→
    91→app.listen(PORT, () => {
    92→  console.log(`Gene Review Dashboard MCP server listening on http://localhost:${PORT}/mcp`);
    93→});
    94→

