     1→import { App } from "@modelcontextprotocol/ext-apps";
     2→
     3→const contentEl = document.getElementById("content")!;
     4→
     5→const ACTION_COLORS: Record<string, string> = {
     6→  ACCEPT: "#22c55e",
     7→  KEEP_AS_NON_CORE: "#60a5fa",
     8→  MODIFY: "#f59e0b",
     9→  REMOVE: "#ef4444",
    10→  MARK_AS_OVER_ANNOTATED: "#f97316",
    11→  UNDECIDED: "#a78bfa",
    12→  NEW: "#06b6d4",
    13→  PENDING: "#94a3b8",
    14→  NO_REVIEW: "#cbd5e1",
    15→};
    16→
    17→const ACTION_ORDER = [
    18→  "ACCEPT",
    19→  "KEEP_AS_NON_CORE",
    20→  "MODIFY",
    21→  "REMOVE",
    22→  "MARK_AS_OVER_ANNOTATED",
    23→  "UNDECIDED",
    24→  "NEW",
    25→  "PENDING",
    26→  "NO_REVIEW",
    27→];
    28→
    29→interface Stats {
    30→  total_genes: number;
    31→  total_annotations: number;
    32→  total_species: number;
    33→  action_counts: Record<string, number>;
    34→  species_gene_counts: Record<string, number>;
    35→}
    36→
    37→function fmt(n: number): string {
    38→  return n.toLocaleString();
    39→}
    40→
    41→function renderDashboard(stats: Stats) {
    42→  const actions = stats.action_counts;
    43→  const maxCount = Math.max(...Object.values(actions), 1);
    44→
    45→  const barRows = ACTION_ORDER.filter((a) => (actions[a] ?? 0) > 0)
    46→    .map((action) => {
    47→      const count = actions[action] ?? 0;
    48→      const pct = ((count / maxCount) * 100).toFixed(1);
    49→      const color = ACTION_COLORS[action] ?? "#94a3b8";
    50→      const label = action.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase());
    51→      return `
    52→        <div class="bar-row">
    53→          <div class="bar-label">${label}</div>
    54→          <div class="bar-track">
    55→            <div class="bar-fill" style="width:${pct}%;background:${color}"></div>
    56→          </div>
    57→          <div class="bar-count">${fmt(count)}</div>
    58→        </div>`;
    59→    })
    60→    .join("");
    61→
    62→  const speciesRows = Object.entries(stats.species_gene_counts)
    63→    .map(([sp, count]) => `<tr><td>${sp}</td><td>${count}</td></tr>`)
    64→    .join("");
    65→
    66→  contentEl.innerHTML = `
    67→    <div class="stats-row">
    68→      <div class="stat-card"><div class="stat-value">${fmt(stats.total_genes)}</div><div class="stat-label">Genes</div></div>
    69→      <div class="stat-card"><div class="stat-value">${fmt(stats.total_annotations)}</div><div class="stat-label">Annotations</div></div>
    70→      <div class="stat-card"><div class="stat-value">${stats.total_species}</div><div class="stat-label">Species</div></div>
    71→      <div class="stat-card"><div class="stat-value">${fmt(actions["ACCEPT"] ?? 0)}</div><div class="stat-label">Accepted</div></div>
    72→    </div>
    73→    <div class="card">
    74→      <h2>Annotations by Review Action</h2>
    75→      ${barRows}
    76→    </div>
    77→    <div class="card">
    78→      <h2>Top Species by Gene Count</h2>
    79→      <table>
    80→        <thead><tr><th>Species</th><th>Genes</th></tr></thead>
    81→        <tbody>${speciesRows}</tbody>
    82→      </table>
    83→    </div>`;
    84→}
    85→
    86→function parseStats(result: { content?: Array<{ type: string; text?: string }> }): Stats | null {
    87→  const text = result.content?.find((c) => c.type === "text")?.text;
    88→  if (!text) return null;
    89→  try {
    90→    return JSON.parse(text) as Stats;
    91→  } catch {
    92→    return null;
    93→  }
    94→}
    95→
    96→// ── MCP App communication ───────────────────────────────────────────────
    97→
    98→const app = new App({ name: "Gene Review Dashboard", version: "1.0.0" });
    99→app.connect();
   100→
   101→// The host pushes the tool result (stats computed by the agent) to the UI
   102→app.ontoolresult = (result) => {
   103→  const stats = parseStats(result);
   104→  if (stats) {
   105→    renderDashboard(stats);
   106→  } else {
   107→    contentEl.innerHTML = '<div class="loading">Could not parse stats.</div>';
   108→  }
   109→};
